sql:
SELECT COUNT(DISTINCT a.student_id) AS total_students
FROM applications a
JOIN merit_match m ON a.student_id = m.student_id AND a.university_id = m.university_id;

external_knowledge:
- University ID 0 is a placeholder and should be replaced with the actual ID of the university of interest;
- The major 'Computer Science' is used as an example and can be replaced with any other major;
- The query provides insights into the university's overall acceptance rate, application count, and merit aid details, as well as the specific acceptance rate for the Computer Science major.

sql:
SELECT AVG(rating) AS average_rating
FROM university_reviews
WHERE university_id = 0;

SELECT average_starting_salary
FROM universities
WHERE name = 'Stanford University';

